seed_files.taskmanager.py:
"""Task management system — monolithic module.

Contains models, validation, storage, scheduling, and reporting.
"""
from dataclasses import dataclass, field, asdict
from typing import Dict, List, Optional, Tuple
from datetime import datetime, timedelta
from enum import Enum
import csv
import io


# ============================================================
# Constants
# ============================================================

PRIORITIES = ["low", "medium", "high", "critical"]
STATUSES = ["todo", "in_progress", "review", "done", "cancelled"]
RECURRING_INTERVALS = ["daily", "weekly", "biweekly", "monthly"]


# ============================================================
# Models
# ============================================================

@dataclass
class Tag:
    name: str
    color: str = "gray"

    def to_dict(self):
        return asdict(self)


@dataclass
class Task:
    id: int
    title: str
    description: str = ""
    priority: str = "medium"
    status: str = "todo"
    project_id: Optional[int] = None
    assignee: Optional[str] = None
    tags: List[str] = field(default_factory=list)
    due_date: Optional[str] = None
    estimated_hours: float = 0.0
    actual_hours: float = 0.0
    recurring: Optional[str] = None
    created_at: str = ""
    updated_at: str = ""

    def to_dict(self):
        return asdict(self)

    @property
    def is_overdue(self) -> bool:
        if not self.due_date or self.status in ("done", "cancelled"):
            return False
        try:
            due = datetime.fromisoformat(self.due_date)
            return datetime.now() > due
        except ValueError:
            return False


@dataclass
class Project:
    id: int
    name: str
    description: str = ""
    status: str = "todo"
    created_at: str = ""

    def to_dict(self):
        return asdict(self)


@dataclass
class TaskFilter:
    status: Optional[str] = None
    priority: Optional[str] = None
    project_id: Optional[int] = None
    assignee: Optional[str] = None
    tag: Optional[str] = None
    overdue_only: bool = False


# ============================================================
# Validation
# ============================================================

def validate_task(data: dict) -> List[str]:
    """Validate task creation/update data. Returns list of errors."""
    errors = []
    if "title" in data:
        if not isinstance(data["title"], str) or len(data["title"].strip()) == 0:
            errors.append("Title must be a non-empty string")
        elif len(data["title"]) > 200:
            errors.append("Title must be 200 characters or less")
    if "priority" in data and data["priority"] not in PRIORITIES:
        errors.append(f"Priority must be one of: {', '.join(PRIORITIES)}")
    if "status" in data and data["status"] not in STATUSES:
        errors.append(f"Status must be one of: {', '.join(STATUSES)}")
    if "estimated_hours" in data:
        if not isinstance(data["estimated_hours"], (int, float)) or data["estimated_hours"] < 0:
            errors.append("Estimated hours must be a non-negative number")
    if "actual_hours" in data:
        if not isinstance(data["actual_hours"], (int, float)) or data["actual_hours"] < 0:
            errors.append("Actual hours must be a non-negative number")
    if "due_date" in data and data["due_date"] is not None:
        try:
            datetime.fromisoformat(data["due_date"])
        except (ValueError, TypeError):
            errors.append("Due date must be a valid ISO format date")
    if "recurring" in data and data["recurring"] is not None:
        if data["recurring"] not in RECURRING_INTERVALS:
            errors.append(f"Recurring must be one of: {', '.join(RECURRING_INTERVALS)}")
    return errors


def validate_project(data: dict) -> List[str]:
    """Validate project creation data. Returns list of errors."""
    errors = []
    if "name" in data:
        if not isinstance(data["name"], str) or len(data["name"].strip()) == 0:
            errors.append("Project name must be a non-empty string")
        elif len(data["name"]) > 100:
            errors.append("Project name must be 100 characters or less")
    if "status" in data and data["status"] not in STATUSES:
        errors.append(f"Status must be one of: {', '.join(STATUSES)}")
    return errors


def validate_assignment(task_id: int, assignee: str) -> List[str]:
    """Validate task assignment. Returns list of errors."""
    errors = []
    if task_id not in _tasks:
        errors.append("Task not found")
    if not assignee or not isinstance(assignee, str):
        errors.append("Assignee must be a non-empty string")
    return errors


# ============================================================
# Storage
# ============================================================

_tasks: Dict[int, Task] = {}
_projects: Dict[int, Project] = {}
_next_task_id: int = 1
_next_project_id: int = 1


def _reset():
    """Reset all stores (for testing)."""
    global _tasks, _projects, _next_task_id, _next_project_id
    _tasks = {}
    _projects = {}
    _next_task_id = 1
    _next_project_id = 1


def create_task(data: dict) -> Tuple[dict, int]:
    """Create a new task."""
    global _next_task_id
    if "title" not in data:
        return {"errors": ["Title is required"]}, 400
    errors = validate_task(data)
    if errors:
        return {"errors": errors}, 400
    now = datetime.now().isoformat()
    task = Task(
        id=_next_task_id,
        title=data["title"],
        description=data.get("description", ""),
        priority=data.get("priority", "medium"),
        status=data.get("status", "todo"),
        project_id=data.get("project_id"),
        assignee=data.get("assignee"),
        tags=data.get("tags", []),
        due_date=data.get("due_date"),
        estimated_hours=data.get("estimated_hours", 0.0),
        recurring=data.get("recurring"),
        created_at=now,
        updated_at=now,
    )
    _next_task_id += 1
    _tasks[task.id] = task
    return task.to_dict(), 201


def get_task(task_id: int) -> Tuple[dict, int]:
    """Get a task by ID."""
    if task_id not in _tasks:
        return {"error": "Task not found"}, 404
    return _tasks[task_id].to_dict(), 200


def update_task(task_id: int, data: dict) -> Tuple[dict, int]:
    """Update an existing task."""
    if task_id not in _tasks:
        return {"error": "Task not found"}, 404
    errors = validate_task(data)
    if errors:
        return {"errors": errors}, 400
    task = _tasks[task_id]
    for key, value in data.items():
        if hasattr(task, key) and key not in ("id", "created_at"):
            setattr(task, key, value)
    task.updated_at = datetime.now().isoformat()
    return task.to_dict(), 200


def delete_task(task_id: int) -> Tuple[dict, int]:
    """Delete a task."""
    if task_id not in _tasks:
        return {"error": "Task not found"}, 404
    del _tasks[task_id]
    return {"message": "Task deleted"}, 200


def list_tasks(task_filter: Optional[TaskFilter] = None) -> Tuple[list, int]:
    """List tasks with optional filtering."""
    tasks = list(_tasks.values())
    if task_filter:
        if task_filter.status:
            tasks = [t for t in tasks if t.status == task_filter.status]
        if task_filter.priority:
            tasks = [t for t in tasks if t.priority == task_filter.priority]
        if task_filter.project_id is not None:
            tasks = [t for t in tasks if t.project_id == task_filter.project_id]
        if task_filter.assignee:
            tasks = [t for t in tasks if t.assignee == task_filter.assignee]
        if task_filter.tag:
            tasks = [t for t in tasks if task_filter.tag in t.tags]
        if task_filter.overdue_only:
            tasks = [t for t in tasks if t.is_overdue]
    return [t.to_dict() for t in tasks], 200


def create_project(data: dict) -> Tuple[dict, int]:
    """Create a new project."""
    global _next_project_id
    if "name" not in data:
        return {"errors": ["Project name is required"]}, 400
    errors = validate_project(data)
    if errors:
        return {"errors": errors}, 400
    project = Project(
        id=_next_project_id,
        name=data["name"],
        description=data.get("description", ""),
        status=data.get("status", "todo"),
        created_at=datetime.now().isoformat(),
    )
    _next_project_id += 1
    _projects[project.id] = project
    return project.to_dict(), 201


def get_project(project_id: int) -> Tuple[dict, int]:
    """Get a project by ID."""
    if project_id not in _projects:
        return {"error": "Project not found"}, 404
    return _projects[project_id].to_dict(), 200


def assign_task(task_id: int, assignee: str) -> Tuple[dict, int]:
    """Assign a task to someone."""
    errors = validate_assignment(task_id, assignee)
    if errors:
        return {"errors": errors}, 400
    task = _tasks[task_id]
    task.assignee = assignee
    task.updated_at = datetime.now().isoformat()
    return task.to_dict(), 200


# ============================================================
# Scheduling
# ============================================================

def get_due_tasks(within_days: int = 7) -> List[dict]:
    """Get tasks due within the specified number of days."""
    cutoff = datetime.now() + timedelta(days=within_days)
    result = []
    for task in _tasks.values():
        if task.due_date and task.status not in ("done", "cancelled"):
            try:
                due = datetime.fromisoformat(task.due_date)
                if due <= cutoff:
                    result.append(task.to_dict())
            except ValueError:
                pass
    return sorted(result, key=lambda t: t["due_date"])


def get_overdue_tasks() -> List[dict]:
    """Get all overdue tasks."""
    result = []
    for task in _tasks.values():
        if task.is_overdue:
            result.append(task.to_dict())
    return result


def schedule_recurring(task_id: int) -> Tuple[dict, int]:
    """Create next occurrence of a recurring task."""
    if task_id not in _tasks:
        return {"error": "Task not found"}, 404
    task = _tasks[task_id]
    if not task.recurring:
        return {"error": "Task is not recurring"}, 400
    if task.status != "done":
        return {"error": "Complete the current task first"}, 400

    interval_map = {
        "daily": timedelta(days=1),
        "weekly": timedelta(weeks=1),
        "biweekly": timedelta(weeks=2),
        "monthly": timedelta(days=30),
    }
    delta = interval_map[task.recurring]

    new_due = None
    if task.due_date:
        try:
            old_due = datetime.fromisoformat(task.due_date)
            new_due = (old_due + delta).isoformat()
        except ValueError:
            pass

    new_data = {
        "title": task.title,
        "description": task.description,
        "priority": task.priority,
        "project_id": task.project_id,
        "assignee": task.assignee,
        "tags": list(task.tags),
        "due_date": new_due,
        "estimated_hours": task.estimated_hours,
        "recurring": task.recurring,
    }
    return create_task(new_data)


def get_timeline(project_id: Optional[int] = None) -> List[dict]:
    """Get timeline of tasks sorted by due date. Optionally filter by project."""
    tasks = list(_tasks.values())
    if project_id is not None:
        tasks = [t for t in tasks if t.project_id == project_id]
    tasks_with_dates = [t for t in tasks if t.due_date]
    return [
        {
            "id": t.id,
            "title": t.title,
            "due_date": t.due_date,
            "status": t.status,
            "priority": t.priority,
        }
        for t in sorted(tasks_with_dates, key=lambda t: t.due_date)
    ]


# ============================================================
# Reporting
# ============================================================

def get_summary() -> dict:
    """Get overall task summary."""
    total = len(_tasks)
    by_status = {}
    by_priority = {}
    for task in _tasks.values():
        by_status[task.status] = by_status.get(task.status, 0) + 1
        by_priority[task.priority] = by_priority.get(task.priority, 0) + 1
    return {
        "total_tasks": total,
        "by_status": by_status,
        "by_priority": by_priority,
        "overdue_count": len(get_overdue_tasks()),
    }


def get_productivity_report(assignee: str) -> dict:
    """Get productivity report for an assignee."""
    tasks = [t for t in _tasks.values() if t.assignee == assignee]
    done = [t for t in tasks if t.status == "done"]
    total_estimated = sum(t.estimated_hours for t in done)
    total_actual = sum(t.actual_hours for t in done)
    return {
        "assignee": assignee,
        "total_tasks": len(tasks),
        "completed_tasks": len(done),
        "completion_rate": round(len(done) / len(tasks), 2) if tasks else 0.0,
        "estimated_hours": total_estimated,
        "actual_hours": total_actual,
        "efficiency": round(total_estimated / total_actual, 2) if total_actual > 0 else 0.0,
    }


def get_project_breakdown(project_id: int) -> Tuple[dict, int]:
    """Get breakdown of tasks in a project."""
    if project_id not in _projects:
        return {"error": "Project not found"}, 404
    project = _projects[project_id]
    tasks = [t for t in _tasks.values() if t.project_id == project_id]
    by_status = {}
    for task in tasks:
        by_status[task.status] = by_status.get(task.status, 0) + 1
    total_estimated = sum(t.estimated_hours for t in tasks)
    total_actual = sum(t.actual_hours for t in tasks)
    return {
        "project": project.to_dict(),
        "total_tasks": len(tasks),
        "by_status": by_status,
        "estimated_hours": total_estimated,
        "actual_hours": total_actual,
        "progress": round(by_status.get("done", 0) / len(tasks), 2) if tasks else 0.0,
    }, 200


def export_csv() -> str:
    """Export all tasks as CSV string."""
    output = io.StringIO()
    writer = csv.writer(output)
    writer.writerow(["id", "title", "priority", "status", "assignee", "due_date", "estimated_hours", "actual_hours"])
    for task in sorted(_tasks.values(), key=lambda t: t.id):
        writer.writerow([
            task.id, task.title, task.priority, task.status,
            task.assignee or "", task.due_date or "",
            task.estimated_hours, task.actual_hours,
        ])
    return output.getvalue()
